        # Validate count is positive (or zero)
        if count >= 0:
            log_value = math.log10(count + 1)
            merged_data.append({
                'ParticipantBarcode': barcode,
                'histological_type': histology,
                'log10_expression': log_value,
                'original_count': count
            })

