    igf2_expression = json.load(f)

# Extract barcodes and histology for LGG patients
lgg_patients = []
for record in lgg_clinical:
    patient_desc = record.get('Patient_description', '')
    histology = record.get('histological_type', '')

    # Skip histology types enclosed in square brackets
    if histology.startswith('[') and histology.endswith(']') and len(histology) > 2:
        continue

    # Extract TCGA barcode from Patient_description
    match = re.search(r'(TCGA-\w+)', patient_desc)
    if match:
        lgg_patients.append({
            'barcode': match.group(1),
            'histology': histology
        })

# Create lookup for IGF2 expression
igf2_dict = {}
for expr in igf2_expression:
    barcode = expr.get('ParticipantBarcode')
    count = expr.get('normalized_count')
    if barcode and count:
        try:
            igf2_dict[barcode] = float(str(count).strip())
        except:
            pass

# Merge data
merged = []
for patient in lgg_patients:
    barcode = patient['barcode']
    histology = patient['histology']

    if barcode in igf2_dict:
        count = igf2_dict[barcode]
        if count >= 0:
            log_val = math.log10(count + 1)
            merged.append({'barcode': barcode, 'histology': histology, 'log10_value': log_val})

# Group by histology
grouped = {}
for item in merged:
    h = item['histology']
    if h not in grouped:
        grouped[h] = []
    grouped[h].append(item['log10_value'])

# Calculate averages
results = {}
for histology, values in grouped.items():
    avg = sum(values) / len(values)
    results[histology] = round(avg, 6)

# Format output
sorted_results = sorted(results.items())
output_lines = [f"{h}: {avg:.4f}" for h, avg in sorted_results]

final_answer = '\n'.join(output_lines) if output_lines else "No data found"

result = {'answer': final_answer, 'patient_count': len(merged), 'histology_count': len(results)}
print('__RESULT__:')
print(json.dumps(result))"}

